def _parse_allowed_chat_ids() -> set[int]:
    raw = os.getenv("TELEGRAM_ALLOWED_CHAT_IDS", "")
    allowed: set[int] = set()
    for value in raw.split(","):
        v = value.strip()
        if not v:
            continue
        try:
            allowed.add(int(v))
        except ValueError:
            continue
    return allowed


class TelegramBotRunner:
    def __init__(self, token: str):
        self.token = token
        self.base_url = f"https://api.telegram.org/bot{token}"
        self.offset = 0
        self.runner = _build_runner()
        self.admin = _build_admin_orchestrator()
        self._intake_sessions: dict[int, IntakeSession] = {}
        self._chat_modes: dict[int, str] = {}
        self._intake_conductor = IntakeConductor(
            anthropic_client=self.runner.anthropic_client,
            prompt_dir=Path(get_env("PROMPTS_DIR", "prompts")),
        )

    def _send_message(self, chat_id: int, text: str) -> None:
        payload = {"chat_id": chat_id, "text": text}
        with httpx.Client(timeout=45) as client:
            r = client.post(f"{self.base_url}/sendMessage", json=payload)
            r.raise_for_status()

    def _parse_business_profile(self, text: str) -> tuple[str, str]:
        cleaned = (text or "").strip()
        command, payload = self._parse_command(cleaned)
        if command == "/plan":
            cleaned = payload

        if "|" in cleaned:
            profile, goal = cleaned.split("|", 1)
            profile = profile.strip().lower().replace(" ", "_")
            goal = goal.strip()
            if profile and goal:
                return profile, goal

        return "rocket_wash", cleaned

    def _parse_command(self, text: str) -> tuple[str, str]:
        cleaned = (text or "").strip()
        if not cleaned.startswith("/"):
            return "", cleaned
        head, _space, tail = cleaned.partition(" ")
        command = head.split("@", 1)[0].lower()
        return command, tail.strip()

    def _send_messages(self, chat_id: int, messages: list[str]) -> None:
        for message in messages:
            cleaned = str(message).strip()
            if cleaned:
                self._send_message(chat_id, cleaned)

    def _handle_workspace_message(self, chat_id: int, text: str) -> None:
        replies = self.admin.handle_message(chat_id=chat_id, text=text)
        self._send_messages(chat_id, replies)

    def _set_mode(self, chat_id: int, mode: str) -> None:
        self._chat_modes[chat_id] = mode

    def _mode(self, chat_id: int) -> str:
        return self._chat_modes.get(chat_id, "work")

    def _looks_like_workspace_request(self, text: str) -> bool:
        lowered = (text or "").strip().lower()
        if not lowered:
            return False
        if lowered.startswith(("/work", "/admin", "/runs", "/memory", "/status", "/agents")):
            return True
        if lowered.startswith("/plan"):
            return False

        workspace_patterns = [
            r"\bwrite\b",
            r"\bsave\b",
            r"\bexport\b",
            r"\bconvert\b",
            r"\bpdf\b",
            r"\.pdf\b",
            r"\bfile\b",
            r"\bfolder\b",
            r"\bdirectory\b",
            r"\brename\b",
            r"\bdelete\b",
            r"\bmove\b",
            r"\bcopy\b",
            r"\binstall\b",
            r"\bpip\b",
            r"\bpackage\b",
            r"\bread\b",
            r"\blist\b",
            r"\bsearch\b",
            r"\bfind\b",
            r"\bedit\b",
            r"\bappend\b",
            r"\brun\b.*\bcommand\b",
            r"\bdesktop\b",
            r"\bworkspace\b",
            # Coding / R&D / Copilot delegation
            r"\bcode\b",
            r"\bscript\b",
            r"\bpython\b",
            r"\bimplement\b",
            r"\bdebug\b",
            r"\brefactor\b",
            r"\btest\b",
            r"\bapi\b",
            r"\bmodule\b",
            r"\bclass\b",
            r"\bfunction\b",
            r"\bcad\b",
            r"\balibre\b",
            r"\bcopilot\b",
            r"\bcodex\b",
            r"\bagent\b",
            r"\brepository\b",
            r"\brepo\b",
            r"\bgit\b",
            r"\bdevelop\b",
            r"\bbuild\b",
        ]
        return any(re.search(pattern, lowered) for pattern in workspace_patterns)

    def _reply_with_agent(self, chat_id: int, text: str) -> None:
        allowed = _parse_allowed_chat_ids()
        if allowed and chat_id not in allowed:
            self._send_message(chat_id, "You are not authorized to use this bot.")
            return

        cleaned = (text or "").strip()
        command, payload = self._parse_command(cleaned)
        if not cleaned:
            self._send_message(
                chat_id,
                "Send /work <request> for operations tasks, /workspace to manage workspace context, or /plan <business_profile>|<goal> for the guided planning pipeline.",
            )
            return

        if cleaned.lower() in {"help"} or command == "/help":
            self._send_message(
                chat_id,
                "Usage:\n/work <request> — default mode for admin, research, coding delegation, and file/tool execution\n/workspace — list available workspaces\n/workspace set <id> — change active workspace context\n/approvals — list pending approvals\n/approve <id> or /reject <id> [reason] — resolve risky action requests\n/sources <query> — inspect retrieval citations\n/reindex — rebuild retrieval index\n/plan <profile>|<goal> — run the guided planning pipeline\n/runs — show recent run outputs\n/cancel — cancel current planning session\n\nProfiles: rocket_wash, raze_development_studios",
            )
            return

        if command in {"/work", "/admin"}:
            self._set_mode(chat_id, "work")
            # Cancel any in-progress intake session so /work always reaches admin.
            self._intake_sessions.pop(chat_id, None)
            if payload:
                self._handle_workspace_message(chat_id, payload)
            else:
                self._send_message(chat_id, "Workspace mode enabled. Send an operations request, or use /workspace to switch context.")
            return

        if command == "/runs":
            self._set_mode(chat_id, "work")
            self._send_messages(chat_id, self.admin.handle_message(chat_id=chat_id, text="/runs"))
            return

        if command == "/plan":
            self._set_mode(chat_id, "plan")

        if cleaned.lower() in {"cancel"} or command == "/cancel":
            if chat_id in self._intake_sessions:
                del self._intake_sessions[chat_id]
                self._send_message(chat_id, "Session cancelled. Send /plan or a new message to start fresh.")
            else:
                self._send_message(chat_id, "No active session to cancel.")
            return

        if self._mode(chat_id) == "work":
            self._handle_work

from __future__ import annotations

import os

import httpx


def _resolve_chat_ids() -> list[int]:
    raw = os.getenv("TELEGRAM_STATUS_CHAT_IDS", "").strip() or os.getenv(
        "TELEGRAM_ALLOWED_CHAT_IDS", ""
    ).strip()
    chat_ids: list[int] = []
    for value in raw.split(","):
        cleaned = value.strip()
        if not cleaned:
            continue
        try:
            chat_ids.append(int(cleaned))
        except ValueError:
            continue
    return chat_ids


def send_status_message(text: str) -> bool:
    token = os.getenv("TELEGRAM_BOT_TOKEN", "").strip()
    chat_ids = _resolve_chat_ids()
    if not token or not chat_ids or not text.strip():
        return False

    base_url = f"https://api.telegram.org/bot{token}"
    with httpx.Client(timeout=20) as client:
        for chat_id in chat_ids:
            response = client.post(
                f"{base_url}/sendMessage",
                json={"chat_id": chat_id, "text": text[:3500]},
            )
            response.raise_for_status()
    return True

import httpx

class AnthropicClient:
    def __init__(self, api_key: str):
        self.api_key = api_key

    def chat(self, model: str, system: str, user: str, options: dict | None = None) -> str:
        """
        Minimal Anthropic Messages API call.
        Adjust max_tokens / headers as needed.
        """
        options = options or {}
        headers = {
            "x-api-key": self.api_key,
            "anthropic-version": "2023-06-01",
            "content-type": "application/json",
        }
        payload = {
            "model": model,
            "max_tokens": int(options.get("max_tokens", 800)),
            "system": system,
            "messages": [{"role": "user", "content": user}],
        }
        if "temperature" in options:
            payload["temperature"] = options["temperature"]
        r = httpx.post("https://api.anthropic.com/v1/messages", headers=headers, json=payload, timeout=180)
        r.raise_for_status()
        data = r.json()
        # content is a list of blocks; we join text blocks
        parts = []
        for block in data.get("content", []):
            if block.get("type") == "text":
                parts.append(block.get("text", ""))
        return "\n".join(parts).strip()

import httpx


class OllamaClient:
    def __init__(self, base_url: str):
        self.base_url = base_url.rstrip("/")

    def chat(self, model: str, system: str, user: str, options: dict | None = None) -> str:
        chat_payload = {
            "model": model,
            "messages": [
                {"role": "system", "content": system},
                {"role": "user", "content": user},
            ],
            "stream": False,
        }
        if options:
            chat_payload["options"] = options

        chat_resp = httpx.post(f"{self.base_url}/api/chat", json=chat_payload, timeout=180)
        if chat_resp.status_code != 404:
            chat_resp.raise_for_status()
            chat_data = chat_resp.json()
            return chat_data["message"]["content"]

        # Compatibility fallback for Ollama variants that expose /api/generate but not /api/chat.
        generate_payload = {
            "model": model,
            "system": system,
            "prompt": user,
            "stream": False,
        }
        if options:
            generate_payload["options"] = options

        gen_resp = httpx.post(f"{self.base_url}/api/generate", json=generate_payload, timeout=180)
        if gen_resp.status_code != 404:
            gen_resp.raise_for_status()
            gen_data = gen_resp.json()
            return str(gen_data.get("response", "")).strip()

        # OpenAI-compatible fallback used by some Ollama-compatible runtimes.
        v1_payload = {
            "model": model,
            "messages": [
                {"role": "system", "content": system},
                {"role": "user", "content": user},
            ],
            "stream": False,
        }
        v1_resp = httpx.post(f"{self.base_url}/v1/chat/completions", json=v1_payload, timeout=180)
        v1_resp.raise_for_status()
        v1_data = v1_resp.json()
        choices = v1_data.get("choices", [])
        if not choices:
            return ""
        message = choices[0].get("message", {})
        return str(message.get("content", "")).strip()

