@dataclass(frozen=True)
class PolicyDecision:
    requires_approval: bool
    reason: str
    category: str


class PolicyEngine:
    """Centralized policy classifier for local and outward actions."""

    DEFAULT_RISKY_TOOLS = {
        "delete_file",
        "rename_path",
        "run_command",
        "install_python_packages",
        "download_file",
        "execute_python",
        "scaffold_tool",
    }

    def __init__(self, config_path: str | Path | None = None):
        self.config_path = Path(config_path) if config_path else None
        self._config = self._load_config()

    def _load_config(self) -> dict[str, Any]:
        if self.config_path and self.config_path.exists():
            payload = yaml.safe_load(self.config_path.read_text(encoding="utf-8"))
            if isinstance(payload, dict):
                return payload
        return {
            "approval": {
                "require_for_tool_names": sorted(self.DEFAULT_RISKY_TOOLS),
                "require_for_categories": [
                    "external_action",
                    "destructive_action",
                    "production_change",
                    "spend_money",
                ],
            }
        }

    def classify_tool_call(self, tool_call: dict[str, Any]) -> PolicyDecision:
        tool_name = str(tool_call.get("tool", "")).strip().lower()
        if tool_name in {"delete_file"}:
            return PolicyDecision(True, "Destructive action requires approval.", "destructive_action")
        if tool_name in {"rename_path", "run_command", "install_python_packages", "download_file", "execute_python", "scaffold_tool"}:
            return PolicyDecision(True, "Potentially risky local action requires approval.", "local_risky_action")
        return PolicyDecision(False, "Safe local action.", "safe_internal_action")

    def tool_calls_require_approval(self, tool_calls: list[dict[str, Any]]) -> PolicyDecision:
        risky_tools = set(self._config.get("approval", {}).get("require_for_tool_names", []))
        for call in tool_calls:
            tool_name = str(call.get("tool", "")).strip().lower()
            if tool_name in risky_tools:
                return self.classify_tool_call(call)
        return PolicyDecision(False, "No approval needed for selected tool calls.", "safe_internal_action")


class ApprovalStore:
    """Persistent approval queue for risky tool/action execution."""

    def __init__(self, state_dir: str | Path = "state"):
        self.state_dir = Path(state_dir)
        self.state_dir.mkdir(parents=True, exist_ok=True)
        self.path = self.state_dir / "pending_approvals.json"

    def _load(self) -> dict[str, Any]:
        if not self.path.exists():
            return {"approvals": []}
        payload = json.loads(self.path.read_text(encoding="utf-8"))
        if not isinstance(payload, dict):
            return {"approvals": []}
        payload.setdefault("approvals", [])
        return payload

    def _save(self, payload: dict[str, Any]) -> None:
        self.path.write_text(json.dumps(payload, indent=2), encoding="utf-8")

    def add_pending(
        self,
        chat_id: int,
        owner_message: str,
        tool_calls: list[dict[str, Any]],
        rationale: str,
        workspace: str,
    ) -> dict[str, Any]:
        payload = self._load()
        approval_id = f"apr-{datetime.now(timezone.utc).strftime('%Y%m%d-%H%M%S-%f')}"
        record = {
            "approval_id": approval_id,
            "chat_id": chat_id,
            "workspace": workspace,
            "owner_message": owner_message,
            "tool_calls": tool_calls,
            "rationale": rationale,
            "status": "pending",
            "created_at": _utc_now(),
            "updated_at": _utc_now(),
            "decision_reason": "",
        }
        payload["approvals"].append(record)
        self._save(payload)
        return record

    def list_pending(self, chat_id: int | None = None) -> list[dict[str, Any]]:
        payload = self._load()
        items = [record for record in payload["approvals"] if record.get("status") == "pending"]
        if chat_id is not None:
            items = [record for record in items if int(record.get("chat_id", -1)) == chat_id]
        return items

    def get(self, approval_id: str) -> dict[str, Any] | None:
        payload = self._load()
        for record in payload["approvals"]:
            if str(record.get("approval_id")) == approval_id:
                return record
        return None

    def resolve(self, approval_id: str, approved: bool, reason: str = "") -> dict[str, Any] | None:
        payload = self._load()
        for record in payload["approvals"]:
            if str(record.get("approval_id")) != approval_id:
                continue
            record["status"] = "approved" if approved else "rejected"
            record["decision_reason"] = reason
            record["updated_at"] = _utc_now()
            self._save(payload)
            return record
        return None

    def mark_executed(self, approval_id: str) -> dict[str, Any] | None:
        payload = self._load()
        for record in payload["approvals"]:
            if str(record.get("approval_id")) != approval_id:
                continue
            record["status"] = "executed"
            record["updated_at"] = _utc_now()
            self._save(payload)
            return record
        return None

from __future__ import annotations

import time
import httpx

MAX_RETRIES = 4
BASE_DELAY = 5.0


class AnthropicClient:
    def __init__(self, api_key: str, default_model: str = "claude-sonnet-4-20250514"):
        self.api_key = api_key.strip()
        self.default_model = default_model

    def chat(self, model: str, system: str, user: str, temperature: float = 0.2, max_tokens: int = 1800) -> dict:
        if not self.api_key:
            raise RuntimeError("Missing ANTHROPIC_API_KEY")

        headers = {
            "x-api-key": self.api_key,
            "anthropic-version": "2023-06-01",
            "content-type": "application/json",
        }
        payload = {
            "model": model,
            "system": system,
            "messages": [{"role": "user", "content": user}],
            "max_tokens": max_tokens,
            "temperature": temperature,
        }

        last_exc: Exception | None = None
        for attempt in range(MAX_RETRIES):
            try:
                with httpx.Client(timeout=180) as client:
                    resp = client.post("https://api.anthropic.com/v1/messages", headers=headers, json=payload)
                if resp.status_code in (429, 500, 502, 503, 504):
                    retry_after = float(resp.headers.get("retry-after", BASE_DELAY * (2 ** attempt)))
                    time.sleep(min(retry_after, 60))
                    last_exc = httpx.HTTPStatusError(resp.text, request=resp.request, response=resp)
                    continue
                resp.raise_for_status()
                break
            except httpx.HTTPStatusError as exc:
                if exc.response.status_code not in (429, 500, 502, 503, 504):
                    raise
                last_exc = exc
                time.sleep(BASE_DELAY * (2 ** attempt))
        else:
            raise last_exc
        data = resp.json()

        parts: list[str] = []
        for block in data.get("content", []):
            if block.get("type") == "text":
                parts.append(str(block.get("text", "")))

        usage = data.get("usage", {})
        return {
            "text": "\n".join(parts).strip(),
            "usage": {
                "input_tokens": usage.get("input_tokens", 0),
                "output_tokens": usage.get("output_tokens", 0),
            },
            "raw": data,
            "provider": "anthropic",
            "model": model,
        }

from __future__ import annotations

import time
import httpx

MAX_RETRIES = 4
BASE_DELAY = 5.0


class OpenAIClient:
    def __init__(
        self,
        api_key: str,
        base_url: str = "https://api.openai.com/v1",
        default_model: str = "gpt-4.1-mini",
    ):
        self.api_key = api_key.strip()
        self.base_url = base_url.rstrip("/")
        self.default_model = default_model

    def chat(self, model: str, system: str, user: str, temperature: float = 0.2, max_tokens: int = 1800) -> dict:
        if not self.api_key:
            raise RuntimeError("Missing OPENAI_API_KEY")

        headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
        }
        payload = {
            "model": model,
            "messages": [
                {"role": "system", "content": system},
                {"role": "user", "content": user},
            ],
            "temperature": temperature,
            "max_tokens": max_tokens,
        }

        last_exc: Exception | None = None
        for attempt in range(MAX_RETRIES):
            try:
                with httpx.Client(timeout=180) as client:
                    resp = client.post(f"{self.base_url}/chat/completions", headers=headers, json=payload)
                if resp.status_code in (429, 500, 502, 503, 504):
                    retry_after = float(resp.headers.get("retry-after", BASE_DELAY * (2 ** attempt)))
                    time.sleep(min(retry_after, 60))
                    last_exc = httpx.HTTPStatusError(resp.text, request=resp.request, response=resp)
                    continue
                resp.raise_for_status()
                break
            except httpx.HTTPStatusError as exc:
                if exc.response.status_code not in (429, 500, 502, 503, 504):
                    raise
                last_exc = exc
                time.sleep(BASE_DELAY * (2 ** attempt))
        else:
            raise last_exc
        data = resp.json()

        choices = data.get("choices", [])
        text = ""
        if choices:
            message = choices[0].get("message", {})
            text = str(message.get("content", "")).strip()

        return {
            "text": text,
            "usage": data.get("usage", {}),
            "raw": data,
            "provider": "openai",
            "model": model,
        }

