import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Any

import yaml


@dataclass(frozen=True)
class RetrievalHit:
    path: str
    score: int
    snippet: str


class RetrievalIndex:
    """Simple file retrieval with lightweight indexing and source citations."""

    def __init__(
        self,
        workspace_root: str | Path,
        config_path: str | Path = "config/retrieval.yaml",
        state_dir: str | Path = "state/retrieval",
    ):
        self.workspace_root = Path(workspace_root).resolve()
        self.config_path = self.workspace_root / Path(config_path)
        self.state_dir = self.workspace_root / Path(state_dir)
        self.state_dir.mkdir(parents=True, exist_ok=True)
        self.index_path = self.state_dir / "index.json"
        self._config = self._load_config()

    def _load_config(self) -> dict[str, Any]:
        if self.config_path.exists():
            payload = yaml.safe_load(self.config_path.read_text(encoding="utf-8"))
            if isinstance(payload, dict):
                return payload
        return {
            "enabled": True,
            "default_citations": True,
            "include_paths": ["README.md", "prompts", "src", "docs", "workspaces"],
            "include_extensions": [".md", ".txt", ".yaml", ".yml", ".toml", ".py", ".json"],
            "max_file_chars": 12000,
        }

    def _include_paths(self) -> list[Path]:
        paths = []
        for raw in self._config.get("include_paths", []):
            path = self.workspace_root / Path(str(raw))
            if path.exists():
                paths.append(path)
        return paths

    def _include_extensions(self) -> set[str]:
        return {str(ext).lower() for ext in self._config.get("include_extensions", [])}

    def _iter_files(self):
        include_ext = self._include_extensions()
        for base in self._include_paths():
            if base.is_file():
                if base.suffix.lower() in include_ext:
                    yield base
                continue
            for path in base.rglob("*"):
                if not path.is_file():
                    continue
                if path.suffix.lower() not in include_ext:
                    continue
                yield path

    def rebuild(self) -> int:
        max_chars = int(self._config.get("max_file_chars", 12000))
        docs: list[dict[str, Any]] = []
        for path in self._iter_files():
            try:
                text = path.read_text(encoding="utf-8", errors="replace")[:max_chars]
            except OSError:
                continue
            docs.append(
                {
                    "path": str(path.relative_to(self.workspace_root)).replace("\\", "/"),
                    "text": text,
                    "tokens": self._tokenize(text),
                }
            )
        payload = {"documents": docs}
        self.index_path.write_text(json.dumps(payload), encoding="utf-8")
        return len(docs)

    def ensure_index(self) -> int:
        if not self.index_path.exists():
            return self.rebuild()
        try:
            payload = json.loads(self.index_path.read_text(encoding="utf-8"))
            if not isinstance(payload, dict) or "documents" not in payload:
                return self.rebuild()
            return len(payload.get("documents", []))
        except json.JSONDecodeError:
            return self.rebuild()

    def _load_index(self) -> list[dict[str, Any]]:
        self.ensure_index()
        payload = json.loads(self.index_path.read_text(encoding="utf-8"))
        docs = payload.get("documents", [])
        if isinstance(docs, list):
            return docs
        return []

    @staticmethod
    def _tokenize(text: str) -> list[str]:
        return re.findall(r"[a-zA-Z0-9_\-/\.]+", text.lower())

    def query(self, query_text: str, limit: int = 5, snippet_chars: int = 360) -> list[RetrievalHit]:
        terms = [t for t in self._tokenize(query_text) if len(t) > 1]
        if not terms:
            return []

        hits: list[RetrievalHit] = []
        for doc in self._load_index():
            tokens = set(doc.get("tokens", []))
            score = sum(1 for term in terms if term in tokens)
            if score <= 0:
                continue
            text = str(doc.get("text", ""))
            snippet = self._build_snippet(text=text, terms=terms, max_chars=snippet_chars)
            hits.append(RetrievalHit(path=str(doc.get("path", "")), score=score, snippet=snippet))

        hits.sort(key=lambda item: item.score, reverse=True)
        return hits[:limit]

    @staticmethod
    def _build_snippet(text: str, terms: list[str], max_chars: int) -> str:
        lowered = text.lower()
        best_index = -1
        for term in terms:
            idx = lowered.find(term)
            if idx != -1:
                best_index = idx
                break
        if best_index == -1:
            return text[:max_chars]

        start = max(best_index - int(max_chars * 0.3), 0)
        end = min(start + max_chars, len(text))
        return text[start:end].replace("\n", " ").strip()

    def render_hits(self, query_text: str, limit: int = 5, include_citations: bool = True) -> str:
        hits = self.query(query_text=query_text, limit=limit)
        if not hits:
            return "No retrieval matches."

        lines = ["Retrieved sources:"]
        for idx, hit in enumerate(hits, start=1):
            source = f"[{hit.path}]" if include_citations else hit.path
            lines.append(f"{idx}. {source} (score={hit.score})")
            lines.append(f"   {hit.snippet}")
        return "\n".join(lines)

from __future__ import annotations

import json
from datetime import datetime, timezone
from pathlib import Path


def _utc_now_compact() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%d-%H%M%S")


class RunStore:
    def __init__(self, runs_dir: str | Path = "runs"):
        self.runs_dir = Path(runs_dir)
        self.runs_dir.mkdir(parents=True, exist_ok=True)

    def save(self, workflow: str, payload: dict) -> Path:
        run_id = payload.get("run_id") or _utc_now_compact()
        path = self.runs_dir / f"{workflow}-{run_id}.json"
        path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
        return path

    def append_index(self, payload: dict, index_name: str = "run_index.jsonl") -> Path:
        path = self.runs_dir / index_name
        with path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(payload) + "\n")
        return path

    def recent_run_summaries(self, limit: int = 5, workflow: str | None = None) -> list[dict]:
        runs: list[tuple[float, Path]] = []
        pattern = f"{workflow}-*.json" if workflow else "*.json"
        for path in self.runs_dir.glob(pattern):
            if not path.is_file() or path.name == "run_index.jsonl":
                continue
            if workflow is None and path.name == "run_index.jsonl":
                continue
            try:
                runs.append((path.stat().st_mtime, path))
            except OSError:
                continue

        summaries: list[dict] = []
        for _, path in sorted(runs, key=lambda item: item[0], reverse=True)[:limit]:
            try:
                payload = json.loads(path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                continue
            summary = {
                "path": str(path),
                "run_id": payload.get("run_id"),
                "workflow": path.stem.split("-", 1)[0],
                "business_profile": payload.get("business_profile"),
                "status": payload.get("status"),
                "confidence": payload.get("confidence"),
                "goal": str(payload.get("goal", ""))[:180],
                "final_summary": str(payload.get("final_memo", {}).get("summary", ""))[:320],
            }
            summaries.append(summary)
        return summaries

    def render_recent_runs(self, limit: int = 5, workflow: str | None = None, max_chars: int = 3000) -> str:
        summaries = self.recent_run_summaries(limit=limit, workflow=workflow)
        if not summaries:
            return "No past runs recorded."

        lines = ["Recent runs:"]
        for item in summaries:
            lines.append(
                f"- {item.get('workflow')} {item.get('run_id')} | {item.get('business_profile')} | {item.get('status')} | confidence={item.get('confidence')}"
            )
            goal = str(item.get("goal", "")).strip()
            if goal:
                lines.append(f"  Goal: {goal}")
            final_summary = str(item.get("final_summary", "")).strip()
            if final_summary:
                lines.append(f"  Summary: {final_summary}")
        return "\n".join(lines)[:max_chars]

from __future__ import annotations

import json
from dataclasses import dataclass, field
from pathlib import Path


@dataclass
class IntakeSession:
    business_profile: str
    history: list[dict] = field(default_factory=list)
    refined_goal: str = ""
    ready: bool = False


def _extract_json(raw: str) -> dict:
    text = raw.strip()
    if "```" in text:
        start = text.find("```")
        end = text.rfind("```")
        if end > start:
            text = text[start + 3 : end].strip()
            if text.lower().startswith("json"):
                text = text[4:].strip()
    start = text.find("{")
    end = text.rfind("}")
    if start != -1 and end > start:
        text = text[start : end + 1]
    try:
        parsed = json.loads(text)
        if isinstance(parsed, dict):
            return parsed
    except json.JSONDecodeError:
        pass
    return {"status": "asking", "message": text}


class IntakeConductor:
    """Drives a clarification conversation using an Anthropic client."""

    def __init__(self, anthropic_client, prompt_dir: Path):
        self.client = anthropic_client
        self.system_prompt = (prompt_dir / "intake.txt").read_text(encoding="utf-8")

    def start(self, session: IntakeSession, initial_text: str) -> str:
        """Process the first user message and return the bot's opening question."""
        session.history.append({"role": "user", "content": initial_text})
        return self._advance(session)

    def reply(self, session: IntakeSession, user_message: str) -> str:
        """Process a follow-up user message and return the bot's next message."""
        session.history.append({"role": "user", "content": user_message})
        return self._advance(session)

    def _advance(self, session: IntakeSession) -> str:
        # Build the user turn from full history as a dialogue block
        dialogue_lines = []
        for turn in session.history:
            role_label = "User" if turn["role"] == "user" else "Assistant"
            dialogue_lines.append(f"{role_label}: {turn['content']}")
        user_block = "\n".join(dialogue_lines)

        response = self.client.chat(
            model=self.client.default_model,
            system=self.system_prompt,
            user=f"Business profile: {session.business_profile}\n\nConversation so far:\n{user_block}",
            temperature=0.3,
            max_tokens=600,
        )

        parsed = _extract_json(response.get("text", ""))
        status = parsed.get("status", "asking")
        message = parsed.get("message", "Could you tell me more about what you're trying to achieve?")

        session.history.append({"role": "assistant", "content": message})

        if status == "ready":
            session.refined_goal = parsed.get("refined_goal", message)
            session.ready = True

        return message

